python3 << 'EOF'
import yaml
import sys

# Define expected value
EXPECTED_MAX_BOOLEAN_CLAUSES = 30000
EXPECTED_FILTER_BOOK_LIMIT = 30000

compose_files = [
    './compose.yaml',
    './compose.override.yaml',
    './compose.production.yaml',
    './scripts/solr_builder/compose.yaml',
]

print("Checking all compose files for SOLR max.booleanClauses alignment...")
print(f"Expected value: {EXPECTED_MAX_BOOLEAN_CLAUSES}\n")

all_aligned = True

for compose_file in compose_files:
    try:
        with open(compose_file, 'r') as f:
            compose_data = yaml.safe_load(f)

        solr_services = []
        for service_name, service_config in compose_data.get('services', {}).items():
            if 'solr' in service_name.lower() and service_config.get('image', '').startswith('solr'):
                solr_services.append((service_name, service_config))

        for service_name, service_config in solr_services:
            env_vars = service_config.get('environment', [])

            # Extract SOLR_OPTS
            solr_opts = None
            for var in env_vars:
                if isinstance(var, str) and var.startswith('SOLR_OPTS='):
                    solr_opts = var
                    break
                elif isinstance(var, dict) and 'SOLR_OPTS' in var:
                    solr_opts = var['SOLR_OPTS']
                    break

            if solr_opts:
                # Extract max.booleanClauses value
                max_clauses = None
                if isinstance(solr_opts, str):
                    parts = solr_opts.split()
                    for part in parts:
                        if 'max.booleanClauses' in part:
                            try:
                                max_clauses = int(part.split('=')[1])
                            except (IndexError, ValueError):
                                pass

                if max_clauses is not None:
                    status = "✓" if max_clauses == EXPECTED_MAX_BOOLEAN_CLAUSES else "✗"
                    print(f"{status} {compose_file} - {service_name}: {max_clauses}")
                    if max_clauses != EXPECTED_MAX_BOOLEAN_CLAUSES:
                        all_aligned = False
                else:
                    print(f"⚠ {compose_file} - {service_name}: max.booleanClauses not found!")
                    all_aligned = False
            else:
                print(f"⚠ {compose_file} - {service_name}: SOLR_OPTS not found!")
                all_aligned = False
    except Exception as e:
        print(f"✗ {compose_file}: Error - {e}")
        all_aligned = False

print("\n" + "="*60)
if all_aligned:
    print("✓ All compose files have max.booleanClauses=30000")
    sys.exit(0)
else:
    print("✗ Some compose files are not aligned!")
    sys.exit(1)
EOF

