import yaml

print("=" * 70)
print("FINAL COMPREHENSIVE VERIFICATION")
print("=" * 70)

compose_files = [
    ('compose.yaml', 'main'),
    ('compose.override.yaml', 'override'),
    ('compose.production.yaml', 'production'),
    ('scripts/solr_builder/compose.yaml', 'solr_builder'),
]

all_correct = True

for filepath, label in compose_files:
    print(f"\n{label.upper()} ({filepath}):")
    with open(filepath) as f:
        data = yaml.safe_load(f)

    found_solr_config = False
    for service_name, service_config in data.get('services', {}).items():
        if 'solr' in service_name.lower():
            # Check if it has a solr image
            image = service_config.get('image', '')
            if image.startswith('solr'):
                found_solr_config = True
                env_vars = service_config.get('environment', [])

                # Find SOLR_OPTS
                solr_opts = None
                for var in env_vars:
                    if isinstance(var, str) and var.startswith('SOLR_OPTS='):
                        solr_opts = var
                        break

                if solr_opts and 'max.booleanClauses' in solr_opts:
                    # Extract value
                    parts = solr_opts.split()
                    for part in parts:
                        if 'max.booleanClauses' in part:
                            value = int(part.split('=')[1])
                            if value == 30000:
                                print(f"  ✓ {service_name}: max.booleanClauses={value}")
                            else:
                                print(f"  ✗ {service_name}: max.booleanClauses={value} (EXPECTED 30000)")
                                all_correct = False
                else:
                    print(f"  ⚠ {service_name}: SOLR_OPTS or max.booleanClauses not found")

    if not found_solr_config:
        print(f"  (No Solr services in this file)")

print("\n" + "=" * 70)
if all_correct:
    print("✓✓✓ SUCCESS: All Solr services properly configured ✓✓✓")
    print("    All values are aligned to 30,000")
else:
    print("✗✗✗ FAILURE: Configuration mismatch detected ✗✗✗")

print("=" * 70)
